#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 1;
const long long INF = 1e18;

long long d[N];
vector<pair<int,int>> adj[N];
bool vis[N];


void dijkstra(int source, int n) {
    for(int i = 1; i <= n; i++) {
        d[i] = INF, vis[i] = false;
    }
    d[source] = 0;

    // n iteration to consider all the vertices
    for(int i = 1; i <= n; i++) {
        int v = -1;
        long long cur = INF;

        for(int j = 1; j <= n; j++) {

            // Update if a closer node found
            if(cur >= d[j] && vis[j] == 0) { 
                v = j;
                cur = d[j];
            }
        }

        vis[v] = 1;

        for(auto edge: adj[v]) {
            int u = edge.first;
            int weight = edge.second;

            // Update the distance of the vertex
            d[u] = min(d[u], weight + d[v]);
        }
    }       
}

int main() {
    int n, m; 
    cin >> n >> m;

    for(int i = 0; i < m; i++) {
        int a, b, w;
        cin >> a >> b >> w;

        // Undirected edge
        adj[a].push_back({b, w});
        adj[b].push_back({a, w});
    }

    dijkstra(1, n);

    // Print the distance
    for(int i = 1; i <= n; i++) {
        if(d[i] == INF) cout << "-1 ";
        else cout << d[i] << " ";
    }

    return 0;
}

