#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>

#define N 100001
#define INF 1000000000000000000LL

long long *d;
int **adj;
int *adj_size;
bool *vis;

void add_edge(int u, int v, int weight) {
    adj[u][adj_size[u]] = v;
    adj[u][adj_size[u] + 1] = weight;
    adj_size[u] += 2;
}

void dijkstra(int source, int n) {
    for (int i = 1; i <= n; i++) {
        d[i] = INF;
        vis[i] = false;
    }
    d[source] = 0;

    for (int i = 1; i <= n; i++) {
        int v = -1;
        long long cur = INF;

        for (int j = 1; j <= n; j++) {
            if (cur >= d[j] && !vis[j]) {
                v = j;
                cur = d[j];
            }
        }

        if (v == -1) break;

        vis[v] = true;

        for (int k = 0; k < adj_size[v]; k += 2) {
            int u = adj[v][k];
            int weight = adj[v][k + 1];
            if (d[u] > weight + d[v]) {
                d[u] = weight + d[v];
            }
        }
    }
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    // Allocate memory for the arrays
    d = (long long *)malloc((n + 1) * sizeof(long long));
    vis = (bool *)malloc((n + 1) * sizeof(bool));
    adj_size = (int *)malloc((n + 1) * sizeof(int));
    adj = (int **)malloc((n + 1) * sizeof(int *));
    for (int i = 0; i <= n; i++) {
        adj[i] = (int *)malloc(2 * (m + 1) * sizeof(int)); // Allocate enough space for edges
        adj_size[i] = 0;
    }

    for (int i = 0; i < m; i++) {
        int a, b, w;
        scanf("%d %d %d", &a, &b, &w);

        // Undirected edge
        add_edge(a, b, w);
        add_edge(b, a, w);
    }

    dijkstra(1, n);

    // Print the distance
    for (int i = 1; i <= n; i++) {
        if (d[i] == INF) printf("-1 ");
        else printf("%lld ", d[i]);
    }

    // Free allocated memory
    free(d);
    free(vis);
    free(adj_size);
    for (int i = 0; i <= n; i++) {
        free(adj[i]);
    }
    free(adj);

    return 0;
}

