import java.util.*;

class main {
    static final int N = 100001;
    static final long INF = 1000000000000000000L;
    static long[] d = new long[N];
    static List<Pair>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];

    static class Pair {
        int node;
        int weight;

        Pair(int node, int weight) {
            this.node = node;
            this.weight = weight;
        }
    }

    static void dijkstra(int source, int n) {
        for (int i = 1; i <= n; i++) {
            d[i] = INF;
            vis[i] = false;
        }
        d[source] = 0;

        // n iterations to consider all the vertices
        for (int i = 1; i <= n; i++) {
            int v = -1;
            long cur = INF;

            for (int j = 1; j <= n; j++) {

                // Update if a closer node found
                if (cur >= d[j] && !vis[j]) {
                    v = j;
                    cur = d[j];
                }
            }

            vis[v] = true;

            for (Pair edge : adj[v]) {
                int u = edge.node;
                int weight = edge.weight;

                // Update the distance of the vertex
                d[u] = Math.min(d[u], weight + d[v]);
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();

        for (int i = 1; i <= n; i++) {
            adj[i] = new ArrayList<>();
        }

        for (int i = 0; i < m; i++) {
            int a = scanner.nextInt();
            int b = scanner.nextInt();
            int w = scanner.nextInt();

            // Undirected edge
            adj[a].add(new Pair(b, w));
            adj[b].add(new Pair(a, w));
        }

        dijkstra(1, n);

        // Print the distance
        for (int i = 1; i <= n; i++) {
            if (d[i] == INF) {
                System.out.print("-1 ");
            } else {
                System.out.print(d[i] + " ");
            }
        }
    }
}
